mapper.update:
UPDATE t_payment_order
SET status = #{status},
    status_type = #{statusType},
    channel_transaction_no = #{channelTransactionNo}
WHERE payment_order_id = #{paymentOrderId}

UPDATE t_prepay_order
SET cashier_status = #{cashierStatus},
    cashier_status_type = #{cashierStatusType}
WHERE payment_order_id = #{paymentOrderId}

UPDATE t_payment_attempt
SET attempt_status = #{attemptStatus},
    attempt_status_type = #{attemptStatusType}
WHERE payment_order_id = #{paymentOrderId}

UPDATE t_order
SET paid_amount = #{paidAmount},
    order_status = #{orderStatus},
    order_status_type = #{orderStatusType}
WHERE order_no = #{orderNo}

UPDATE t_bill
SET paid_amount = #{paidAmount},
    bill_status = #{billStatus},
    bill_status_type = #{billStatusType}
WHERE order_no = #{orderNo}
